(660, '36', 191, 'CAM-2025-0114', 'REPORTE CERRADO DE CONFORMIDAD - SIN OBSERVACIONES', 'CERRADO', 'JOHANNA.ALEMAN', '2025-09-24 08:04:45'),
(661, '36', 195, 'CAM-2025-0118', 'SE RECIBE MOFFETT, EL 23 DE SEPT AL MEDIO DíA,\r\nSE HACE REQUERIMIENTO DE FILTROS\r\nADICIONAL A ESTO TIENE FUGAS DE ACEITE HIDRáULICO\r\nSE LE PERDIó AL OPERADOR UNA PIEZA QUE SOSTIENE CILINDRO DE LEVANTE ESTA PIEZA SE TIENE QUE FABRICAR EN TALLER EXTERNO (TORNO)', 'EN PROGRESO', 'ANGEL.CONTRERAS', '2025-09-24 08:11:59'),
(662, '7', 196, 'CAM-2025-0119', 'LA FUGA NO ES DE ACEITE, EL PROBLEMA ES FUGA UREA CUANDO ESTE HACE SU REGENERACIóN (AUTOLIMPIEZA), \r\nSE LIMPIO áREA Y SE REAJUSTARON ABRAZADERAS', 'ATENDIDO', 'ANGEL.CONTRERAS', '2025-09-24 08:15:51'),
(663, '39', 199, 'CAM-2025-0122', 'SE REALIZA SERVICIO PREVENTIVO Y SE REPARAN LUCES DELANTERAS Y CUARTOS, SE ENTREGA UNIDAD ENGRASADA Y FUNCIONADO, TRABAJO REALIZADO EL 23 SEPT 2025, EN TALLER NORTE.\r\nPRóXIMO PREVENTIVO 16325 HORAS.', 'ATENDIDO', 'ANGEL.CONTRERAS', '2025-09-24 08:23:19'),
(664, '36', 200, 'CAM-2025-0123', 'SE INICIA EL DESARME PARA LLEVAR A TALLER EXTERNO PARA QUE SE FABRIQUE PIEZA EXTRAVIADA', 'EN ESPERA', 'ANGEL.CONTRERAS', '2025-09-24 08:25:48'),
