(672, '7', 201, 'CAM-2025-0124', 'SE ENCONTRó UN CABLE DE SEñAL SUELTO Y FUSIBLE DAñADO, SE REINSTALA CABLE Y FUSIBLE QUEDANDO EN SERVICIO, AUN ASí, TéCNICO FUE A SITIO CON CLIENTE Y LA BOMBA FUNCIONO CON NORMALIDAD, MECáNICO QUE ATENDO MIGUEL DE TALLER NORTE', 'ATENDIDO', 'ANGEL.CONTRERAS', '2025-09-25 07:22:15'),
(673, '39', 202, 'CAM-2025-0125', 'SE INICIA DIAGNOSTICO ENCONTRANDO BALERO DE FLECHA DAñADO Y FUGA DE ACEITE EN SELECTOR EN TALLER SUR, SE PRECEDE AL DESARME Y A ENVIAR BOMBA A TALLER NORTE, 24 SEPT 2025.', 'EN PROGRESO', 'ANGEL.CONTRERAS', '2025-09-25 07:27:08'),
(674, '7', 203, 'CAM-2025-0126', 'SE ATIENDE PROBLEMA EN CARRETERA, SE LOGRó HACER LLEGAR A TALLER NORTE, ENCONTRANDO DAñO EN BASE DE FILTRO SECADO, EN ESPERA DE QUE LLEGUE REFACCIóN', 'EN PROGRESO', 'ANGEL.CONTRERAS', '2025-09-25 07:31:34'),
