(1382, '35', 355, 'CAM-2026-0072', 'SE DETECTA RELEAY QUEMADO ACTIVA OLLA, SE CAMBIó RELAY SE REINSTALA FUSIBLE DE 7.5 AMPERES, SE CONTINúA REVISANDO Y SE DETECTA VáLVULA DE CONTROL DE OLLA CON AMPERAJE ALTO, SE SOLICITA ESTA VáLVULA, EN ESPERA QUE LLEGUE', 'EN PROGRESO', 'ANGEL.CONTRERAS', '2026-04-09 20:03:28'),
(1383, '7', 375, 'CAM-2026-0092', 'REPORTE CERRADO DE CONFORMIDAD - SIN OBSERVACIONES', 'CERRADO', 'EVANY.FABRO', '2026-04-10 07:48:35'),
